@lru_cache(maxsize=256)
def brand_icon(service_type: str, size: int = 24, fill: str = '') -> QPixmap:
    """Return a QPixmap with the brand SVG icon, or empty pixmap if unknown.

    Args:
        fill: Override fill color (e.g. '#FFFFFF' for white icon on colored box).
              If empty, uses the brand's own color.
    """
    data = _BRAND_DATA.get(service_type)
    if not data:
        return QPixmap()
    path_d, color_hex = data
    icon_fill = fill if fill else color_hex
    svg = (
        f'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"'
        f' width="{size}" height="{size}">'
        f'<path d="{path_d}" fill="{icon_fill}"/>'
        f'</svg>'
    )
    renderer = QSvgRenderer(QByteArray(svg.encode()))
    px = QPixmap(size, size)
    px.fill(Qt.transparent)
    painter = QPainter(px)
    renderer.render(painter)
    painter.end()
    return px


def has_brand_icon(service_type: str) -> bool:
    return service_type in _BRAND_DATA
